-- ============================================================
-- SKILL DETAIL EXPLANATIONS (detail_json and prompt_text)
-- ============================================================

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to turn a collection of strategic inputs into a coherent planning narrative that can be shared with internal stakeholders. It does not decide strategy. Instead, it helps package strategy into a readable, aligned, and outcome-oriented story."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest strategic inputs such as company goals, leadership priorities, prior-quarter reviews, and roadmap themes"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify recurring strategic threads"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"draft a narrative explaining what the team is focusing on, why those areas matter, and how they connect to broader goals"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"surface tensions or tradeoffs that should be explicitly acknowledged"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"generate a concise executive summary and a more complete planning narrative"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because product planning often involves reassembling the same information into multiple stakeholder-ready formats. This skill reduces that manual writing work."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standalone when a PM or product leader needs a draft planning narrative"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"orchestrated as part of a quarterly planning workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required for final framing, tone, and tradeoff clarity"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should validate that the narrative reflects actual decisions rather than merely sounding polished"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ground the skill in structured planning inputs rather than freeform prompting alone"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"outputs should remain editable"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid implying certainty where decisions are still open"}]}]}]}]}' WHERE title = 'Planning Narrative Generator';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to convert high-level strategic direction into product outcomes that are clearer, more measurable, and more useful for downstream planning. Many leadership goals are directional but not yet structured in a way that supports prioritization or measurement. This skill helps bridge that gap."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest high-level goals, strategic statements, or planning themes"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify product-relevant implications"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"draft candidate outcomes phrased in an outcome-oriented way rather than as feature commitments"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"suggest associated success statements or indicators"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"help distinguish true outcomes from activities or outputs"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is valuable because teams often jump from broad goals to initiative lists without clearly defining the outcome they want to change."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standalone during planning and roadmap authoring"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"orchestrated ahead of scenario comparison or prioritization"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required to ensure outcomes reflect real business intent"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should confirm that outcomes are meaningful, measurable, and not just reworded activity lists"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"prefer concise outcome statements"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid creating metrics that look precise but are not grounded in actual measurement capability"}]}]}]}]}' WHERE title = 'Outcome Drafting Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to generate structured comparisons among multiple planning or investment scenarios. It supports decision-making by making tradeoffs visible, but it should not replace human prioritization judgment."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest candidate initiatives, themes, or problem spaces"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"consider available capacity, strategic fit, urgency, confidence, and major risks"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"produce side-by-side planning scenarios"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"articulate what each scenario optimizes for"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"highlight tradeoffs, dependencies, and likely downsides"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful when leadership needs to compare options such as:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"a more ambitious roadmap versus a more focused one"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"a customer-retention-heavy quarter versus an innovation-heavy quarter"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"a low-risk plan versus a high-upside bet"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standalone during roadmap and planning discussions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"orchestrated within a quarterly planning workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required for final scenario selection"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should review the assumptions and weights used to generate comparisons"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"expose assumptions clearly"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"scoring logic should be inspectable and not treated as objective truth"}]}]}]}]}' WHERE title = 'Scenario Comparison Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to convert heterogeneous input records from many sources into a shared signal schema. In an AI-assisted PDLC, useful discovery depends on consistent structure across inputs, whether they arrive from uploaded files or direct system connections."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"receive parsed source records from files or connected systems"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"map those records into a canonical signal model"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"preserve links back to the original record or evidence source"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standardize key metadata fields such as source type, segment, product area, journey stage, and source date"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"flag records that are incomplete, malformed, or difficult to normalize with confidence"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because discovery evidence often comes from incompatible formats and systems. Without normalization, every downstream synthesis activity becomes noisier and less reliable."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"typically part of a broader signal intake workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"needed for low-confidence mappings or schema exceptions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should periodically review normalization quality and source mapping rules"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"preserve traceability"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"work closely with non-AI intake and connector infrastructure"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"do not silently discard ambiguous data"}]}]}]}]}' WHERE title = 'Normalization Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to enrich normalized discovery records with meaningful tags that make downstream synthesis possible. It helps the product organization sort raw signals into consistent categories without requiring manual tagging of every item."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"analyze normalized records"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"assign metadata such as product area, segment, journey stage, issue type, source type, or signal category"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"attach confidence levels to classifications"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"support review of low-confidence classifications"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"produce structured enriched records for later clustering and synthesis"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is valuable because the same raw signal can otherwise remain trapped in unstructured notes, transcripts, or exports. Classification makes patterns discoverable."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"usually run after normalization and before deduplication or clustering"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"recommended for low-confidence or high-impact classifications"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should review and tune classification categories over time"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"do not overfit to one team vocabulary"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"classification taxonomies should be configurable and aligned to the organization product model"}]}]}]}]}' WHERE title = 'Signal Classification Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to identify overlapping or near-duplicate signals across different inputs and systems. The same customer pain point often appears in multiple places, such as support tickets, sales notes, interview transcripts, and survey responses. This skill reduces overcounting and repeated synthesis effort."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"compare normalized and classified signals"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify exact duplicates and near-duplicates"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"group similar signals into canonical clusters"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"preserve links to all supporting source evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"distinguish between repeated evidence and genuinely different issues"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because it helps the organization avoid mistaking duplicate reporting for broader signal diversity."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"usually part of the intake workflow before discovery synthesis"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"needed for borderline duplicate groups"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should review whether grouped signals are meaningfully the same or merely related"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"reduce noise without collapsing important nuance"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"confidence scoring matters when grouping semantically similar issues"}]}]}]}]}' WHERE title = 'Deduplication Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to group enriched discovery signals into broader themes that can be synthesized into actionable product understanding. It helps the team move from record-level evidence to pattern-level insight."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest classified and deduplicated records"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"detect recurring topics, pain points, requests, or breakdowns"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"cluster evidence into coherent themes"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"provide representative evidence for each cluster"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"support segment-level or source-level theme views"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is valuable because product teams often spend a large amount of manual effort trying to answer what keeps coming up. This skill accelerates that work while improving consistency."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"usually part of a discovery synthesis workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"recommended to validate whether the resulting theme groupings are meaningful"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should confirm that important minority signals are not lost in dominant clusters"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"themes should remain evidence-backed"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"clustering should surface uncertainty and not imply that all grouped items are identical"}]}]}]}]}' WHERE title = 'Theme Clustering Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to convert theme clusters into concise, evidence-backed insights that a product team can use in decision-making. It is a synthesis tool, not just a summarization tool."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest clustered themes and supporting evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"produce insight statements that explain what appears to be happening"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"include representative evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify likely implications for product understanding"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"keep the synthesis grounded in traceable source material"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because teams need more than grouped evidence. They need interpretable summaries that preserve nuance and credibility."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"commonly part of the discovery synthesis workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"recommended before insights move into hypothesis formation"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should confirm that summaries are evidence-backed and not overgeneralized"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"emphasize evidence traceability"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid flattening uncertainty into overly polished certainty"}]}]}]}]}' WHERE title = 'Insight Summarization Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to identify where signals disagree across sources, segments, channels, or customer groups. Discovery quality improves when contradiction is surfaced rather than smoothed away."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"compare themes and evidence across dimensions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify disagreements, inconsistencies, or segment-specific variation"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"flag where one customer group reports a different experience from another"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"explain the contradiction in a structured way"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"support follow-up investigation"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because product teams often over-index on the dominant narrative and miss cases where the truth is more conditional or segmented."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"typically run during synthesis, before hypotheses are framed"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"recommended for interpretation of important contradictions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should determine whether contradictions imply different segments, weak data quality, or unresolved product complexity"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"contradictions should be explicit and reviewable"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"do not try to resolve disagreements automatically"}]}]}]}]}' WHERE title = 'Contradiction Detection Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to suggest plausible underlying causes for the patterns identified in discovery. It helps the team prepare for hypothesis formation by moving one level deeper than surface symptom summaries."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest synthesized themes and supporting evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify possible structural or workflow-level causes"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"generate root-cause candidates rather than definitive diagnoses"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"connect proposed causes to observed evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"highlight where more evidence is needed before confidence is warranted"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because teams often stop at symptoms, which leads to weak or reactive solutions."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standalone or near the end of the synthesis workflow"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"frequently used to prepare inputs for Hypothesize and Frame"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required before root-cause candidates are treated as planning inputs"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should decide which candidates are strong enough to carry forward"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"outputs should remain framed as hypotheses, not facts"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"expose uncertainty and evidence gaps clearly"}]}]}]}]}' WHERE title = 'Root Cause Candidate Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to identify what is still missing from the discovery picture. It helps prevent teams from moving forward with a false sense of confidence."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"inspect synthesized discovery outputs"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify weakly supported conclusions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"flag where certain segments, sources, or time windows are underrepresented"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"suggest follow-up questions or data needed"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"support better decision hygiene before framing and prioritization"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because good product decisions depend not only on what is known, but also on a clear view of what remains unknown."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standalone during research review"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"or orchestrated as the final quality gate in discovery synthesis"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required to determine whether missing evidence is tolerable or blocking"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should decide what additional discovery is worth pursuing"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"be conservative"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"favor surfacing uncertainty over filling it in speculatively"}]}]}]}]}' WHERE title = 'Evidence Gap Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to transform discovery insights into explicit candidate hypotheses that can guide product thinking. It helps the team move from what we observed to what we believe may be true and worth testing."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest discovery synthesis and evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"generate candidate hypotheses tied to observed patterns"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"articulate assumptions embedded in each hypothesis"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"indicate confidence and supporting evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"suggest which hypotheses appear strongest or most actionable"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because it creates a disciplined bridge between discovery and product framing."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"commonly the first skill in the framing workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required before hypotheses are treated as active bets"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should ensure hypotheses are specific, testable, and decision-useful"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"hypotheses should stay tied to evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid vague, generic, or solution-biased outputs"}]}]}]}]}' WHERE title = 'Hypothesis Generator';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to turn candidate hypotheses into clear product problem statements. It helps define what the problem is, who experiences it, why it matters, and where the boundaries of the problem should be drawn."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest candidate hypotheses and evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"draft clear problem statements"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify affected users or segments"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"distinguish the core problem from downstream symptoms"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"define in-scope and out-of-scope boundaries"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because teams often move too quickly from insights to solutions without properly defining the problem."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"typically follows hypothesis generation"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required to validate framing and ensure it reflects product reality"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should confirm that the framing is sharp enough to guide prioritization and solutioning"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"keep the framing concise and usable"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid turning every problem into a broad strategic essay"}]}]}]}]}' WHERE title = 'Problem Framing Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to turn framed problems into structured opportunity briefs that can be reviewed, prioritized, and used downstream in the PDLC."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest framed problems and strategic context"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"summarize the opportunity in a consistent structure"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"connect customer impact and business relevance"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"include supporting evidence, assumptions, and open questions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"package the result into a reusable planning artifact"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because it standardizes how potential bets are described and compared."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"often used before prioritization and KPI design"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"recommended before an opportunity brief becomes an input to prioritization"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should validate relevance, clarity, and completeness"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"keep briefs structured and concise"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"preserve traceability back to evidence"}]}]}]}]}' WHERE title = 'Opportunity Brief Generator';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to help compare opportunities using explicit criteria such as impact, urgency, strategic fit, confidence, effort, and dependency risk. It is decision support, not decision replacement."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest opportunity briefs and scoring criteria"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"generate ranked comparisons or scenario views"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"explain why items are being ordered as they are"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"surface tradeoffs and uncertainty"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify which items may need more evidence before prioritization"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because prioritization is often inconsistent, hard to explain, or overly dependent on recent anecdotes."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"often used in product planning and investment review"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required for final prioritization decisions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should review criteria, weighting, and assumptions"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"make logic transparent"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"do not present prioritization as objective truth"}]}]}]}]}' WHERE title = 'Prioritization Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to propose success metrics and measurement structures for selected opportunities. It helps ensure that downstream validation and learning are possible."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest selected opportunities and business goals"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"draft leading and lagging indicators"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"propose success thresholds"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify instrumentation implications"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"help distinguish meaningful metrics from vanity metrics"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because weak success definitions upstream create low-value learning downstream."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"commonly used before PRD generation or validation planning"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required to ensure metrics are actually measurable and decision-relevant"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should confirm instrumentation feasibility"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"keep KPI design grounded in existing analytics capability"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid fake precision"}]}]}]}]}' WHERE title = 'KPI Design Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to turn an approved opportunity into a draft initiative brief or PRD. It reduces the manual burden of translating earlier strategic and framing work into an execution-ready document."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest opportunity briefs, KPI definitions, and constraints"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"draft a PRD or initiative brief"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"include problem context, goals, users, constraints, assumptions, and risks"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"produce acceptance criteria and open questions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"preserve linkage to the original framing work"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because a large amount of PM time is often spent rewriting information that already exists upstream."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"commonly part of build preparation"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required before sharing with design, engineering, or leadership"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should check for clarity, feasibility, and correctness"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"keep the output practical rather than overly long"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"reduce repetition across sections"}]}]}]}]}' WHERE title = 'PRD Authoring Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to help design how an initiative or feature should be validated. It supports rollout planning, decision thresholds, and measurement structure."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest the PRD, KPI definitions, and rollout constraints"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"propose experiment structure, rollout plans, holdbacks, or staged release options"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"suggest success and failure conditions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify risks to interpretation"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"produce a validation-oriented experiment brief"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because many teams want to test changes, but experiment design is often inconsistent or under-specified."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"usually part of build and validation planning"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required before experiments are operationalized"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should review whether the proposed design is feasible and ethically appropriate"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"keep experiments aligned to business questions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"clearly separate assumptions from evidence"}]}]}]}]}' WHERE title = 'Experiment Design Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to transform an approved initiative brief into role-specific execution materials for design, engineering, QA, and support. It reduces handoff friction and duplicated interpretation work."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest the approved initiative brief"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"generate tasks, checklists, review prompts, and supporting execution artifacts"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"tailor outputs for different functions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify dependencies and readiness questions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"create a more build-ready package without requiring each team to reinterpret the same source document from scratch"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because a large amount of waste in the PDLC comes from translation between teams."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"often run after PRD approval"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"recommended before distribution to downstream teams"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should validate task decomposition and role-specific relevance"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"keep outputs practical and lightweight"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"do not create excessive artifacts just because automation makes it easy"}]}]}]}]}' WHERE title = 'Delivery Pack Generator';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to act as a quality-support reviewer for initiative briefs and acceptance criteria. It looks for ambiguity, missing cases, failure modes, and workflow breakdowns that may not be obvious in the first draft."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"inspect PRDs and acceptance criteria"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify likely edge cases, missing scenarios, and ambiguity"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"surface quality questions and risk prompts"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"support better review before implementation begins"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because many delivery issues come from what was omitted, not what was explicitly specified."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standalone during design, PM, or engineering review"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"can also be part of the build preparation workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required to decide which flagged issues matter"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should integrate relevant findings into the execution package"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"focus on usefulness over volume"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid overwhelming teams with generic possible issues"}]}]}]}]}' WHERE title = 'Edge Case Reviewer';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to synthesize what happened after an initiative ships or a feature is exposed. It combines qualitative and quantitative signals into a usable learning summary."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest analytics, feedback, release metadata, and support signals"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"summarize adoption, friction, and outcome changes"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"cluster recurring post-launch issues"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify candidate follow-up actions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"create a structured learning summary for the product team"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because many teams collect post-launch data but struggle to turn it into coherent learning quickly."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"commonly the first skill in the learning workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"recommended before findings are used for roadmap changes"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should confirm whether interpretations are accurate and materially relevant"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"preserve source traceability"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid overstating causality"}]}]}]}]}' WHERE title = 'Post-Launch Learning Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to turn dashboards, KPI movement, and performance shifts into readable plain-language narratives. It helps teams and stakeholders understand what changed without requiring everyone to interpret raw charts."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest analytics snapshots, baselines, and targets"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"summarize what moved, by how much, and in which direction"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"suggest plausible drivers of change"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"call out areas requiring attention"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"tailor explanations into a concise narrative"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because raw data often does not communicate the meaning of change clearly."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"useful in recurring reviews and stakeholder communication"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"recommended when interpreting important changes"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should distinguish plausible drivers from confirmed causes"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"prioritize clarity over verbosity"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"do not overstate explanation confidence"}]}]}]}]}' WHERE title = 'Insight Narrator';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to flag unusual product or metric behavior that may indicate a regression, adoption issue, instrumentation problem, or unexpected usage pattern."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest KPI and usage data"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify unusual patterns or sharp deviations"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"flag changes that warrant review"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"suggest candidate explanations or categories of concern"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"support downstream investigation"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because teams often discover important issues too late when they rely only on manual monitoring."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"often part of a recurring post-launch monitoring flow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required before operational decisions are made based on anomaly output"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should determine whether flagged changes are meaningful or expected"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"false positives should be managed carefully"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"keep anomaly criteria interpretable where possible"}]}]}]}]}' WHERE title = 'Anomaly Detection Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to help the team reconsider roadmap positioning based on newly available evidence. It does not automatically move roadmap items. It provides a recommendation layer."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest post-launch learning, current roadmap context, and strategic priorities"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify where priorities may need reconsideration"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"suggest roadmap changes or confidence updates"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"explain the rationale behind those suggestions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"help connect learning back into planning"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because roadmap maintenance is often periodic and manual, even when new evidence arrives continuously."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standalone ahead of roadmap reviews"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"or near the end of the learning workflow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required for any actual roadmap change"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should evaluate organizational tradeoffs and leadership context"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"frame outputs as recommendations"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid presenting roadmap movement as automatic or purely data-driven"}]}]}]}]}' WHERE title = 'Roadmap Refresh Assistant';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to create audience-specific communication and enablement materials from a shared source package. It helps the organization explain what changed, why it matters, and how different teams should talk about it."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest release summaries, initiative briefs, and audience definitions"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"generate content tailored to internal and external audiences"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"create artifacts such as FAQs, release notes, internal enablement summaries, and communication drafts"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"preserve consistency across channels while adapting tone and detail level"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because downstream launch communication is often repetitive and duplicated across teams."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"both standalone and orchestrated"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"typically part of launch and post-launch communication work"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required for final messaging and approval"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should ensure tone, accuracy, and audience fit"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"generate only the content people are likely to use"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"avoid content sprawl"}]}]}]}]}' WHERE title = 'Launch Content Generator';

UPDATE step_items SET prompt_text = '', detail_json = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"This skill is intended to help keep process and operating documentation current by comparing how work is actually being executed against the current documented playbooks."}]},{"type":"paragraph","content":[{"type":"text","text":"The skill should:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ingest current playbooks, workflow artifacts, and recent lessons learned"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"identify stale, missing, or inconsistent process documentation"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"propose updates or redlines"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"flag where real practice has drifted from documented expectations"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"support ongoing process maintenance"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"This skill is useful because organizations often allow documentation to decay until it no longer reflects reality."}]},{"type":"paragraph","content":[{"type":"text","text":"Best use:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"standalone as a periodic operating-system maintenance tool"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"optionally part of a broader downstream process improvement flow"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Human oversight:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"required before documentation changes are accepted"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"humans should decide which changes are real improvements versus temporary workarounds"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Implementation notes:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"preserve clarity and structure"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"help reduce process drift without generating unnecessary documentation churn"}]}]}]}]}' WHERE title = 'Playbook Update Assistant';
